import { useEffect, useState, useContext } from "react";
import api from "../api";
import { AuthContext } from "../AuthContext";
import styles from "../styles/Appointments.module.css";

export default function Appointments() {
  const { role } = useContext(AuthContext); // получаем роль
  const [appointments, setAppointments] = useState([]);
  const [doctors, setDoctors] = useState([]);
  const [doctorId, setDoctorId] = useState("");
  const [date, setDate] = useState("");

  useEffect(() => {
    loadAppointments();
    if (role === "patient") loadDoctors();
  }, [role]);

  const loadAppointments = async () => {
    const res = await api.get("/appointments");
    setAppointments(res.data);
  };

  const loadDoctors = async () => {
    const res = await api.get("/doctors");
    setDoctors(res.data);
  };

  const createAppointment = async () => {
    if (!doctorId || !date) {
      alert("Select doctor and date");
      return;
    }

    await api.post("/appointments", {
      doctor_id: doctorId,
      appointment_date: date,
    });

    setDoctorId("");
    setDate("");
    loadAppointments();
  };

  return (
    <div className={`appointments ${styles.appointments}`}>
      <h3>Appointments</h3>

      {/* Показываем форму только для пациента */}
      {role === "patient" && (
        <div className={styles.appointmentsForm}>
          <select value={doctorId} onChange={(e) => setDoctorId(e.target.value)}>
            <option value="">Select doctor</option>
            {doctors.map((d) => (
              <option key={d.id} value={d.id}>
                {d.full_name} — {d.specialization}
              </option>
            ))}
          </select>

          <input
            type="datetime-local"
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />

          <button onClick={createAppointment}>Create</button>
        </div>
      )}

      <hr />

      {appointments.map((a) => (
        <div key={a.id} className={styles['appointment-item']}>
          {a.doctor_name} - {a.patient_name} - {a.status}
        </div>
      ))}
    </div>
  );
}
